package images

import (
	"context"
	"encoding/base64"
	"fmt"
	"log"
	"mime"
	"os"

	"google.golang.org/genai"
)

var model = "gemini-3-pro-image-preview"

func main() {
	ctx := context.Background()

	client, err := genai.NewClient(ctx, nil)
	if err != nil {
		log.Fatal(err)
	}

	var tools []*genai.Tool
	tools = append(tools, &genai.Tool{
		GoogleSearch: &genai.GoogleSearch{},
	})

	contents := []*genai.Content{
		{
			Role: "user",
			Parts: []*genai.Part{
				func() *genai.Part {
					data := "" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						""
					decoded, _ := base64.StdEncoding.DecodeString(data)
					part := &genai.Part{
						InlineData: &genai.Blob{
							Data:     decoded,
							MIMEType: "image/jpeg",
						},
					}
					return part
				}(),
				func() *genai.Part {
					data := "" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						"" +
						""
					decoded, _ := base64.StdEncoding.DecodeString(data)
					part := &genai.Part{
						InlineData: &genai.Blob{
							Data:     decoded,
							MIMEType: "image/jpeg",
						},
					}
					return part
				}(),
				genai.NewPartFromText("你是一个摄影师，拍摄一张陈博士(man.jpg)站着教堂(background.jpg)的近身照片。"),
			},
		},
	}

	config := &genai.GenerateContentConfig{
		ResponseModalities: []string{
			"IMAGE",
			"TEXT",
		},
		ImageConfig: &genai.ImageConfig{
			ImageSize: "1K",
		},
		Tools: tools,
	}

	for result, err := range client.Models.GenerateContentStream(ctx, model, contents, config) {
		if err != nil {
			log.Fatal(err)
		}

		if len(result.Candidates) == 0 || result.Candidates[0].Content == nil || len(result.Candidates[0].Content.Parts) == 0 {
			continue
		}

		parts := result.Candidates[0].Content.Parts
		for _, part := range parts {
			if part.InlineData != nil {
				fileName := "ENTER_FILE_NAME"
				fileExtension := ""
				if part.InlineData.MIMEType != "" {
					exts, err := mime.ExtensionsByType(part.InlineData.MIMEType)
					if err != nil {
						log.Fatal(err)
					}
					if len(exts) > 0 {
						fileExtension = exts[0][1:]
					}
				}
				err := os.WriteFile(fileName+"."+fileExtension, part.InlineData.Data, 0644)
				if err != nil {
					fmt.Printf("Error writing file: %v\n", err)
					return
				}
				fmt.Printf("Saved file: %s\n", fileName)
			} else {
				fmt.Print(part.Text)
			}
		}
	}
}
